// Filter & Parse - Kapso WhatsApp Cloud API webhook payload
const items = $input.all();
const body = items[0].json.body || items[0].json;

// Kapso v2 payload structure:
// { message: { id, type, text: { body }, kapso: { direction, content, has_media } },
//   conversation: { id, phone_number }, is_new_conversation, phone_number_id }

const msg = body.message;
if (!msg) return [];

// Ignore outbound messages (sent by us)
if (msg.kapso?.direction !== 'inbound') return [];

const phone = (body.conversation?.phone_number || '').replace('+', '');
if (!phone) return [];

const phoneNumberId = body.phone_number_id || '';
const isNewConversation = body.is_new_conversation === true;

// Determine message type and extract content
const msgType = msg.type || 'text';
let messageType = 'text';
let text = '';
let mediaInfo = null;

if (msgType === 'text') {
  messageType = 'text';
  text = msg.text?.body || msg.kapso?.content || '';
} else if (msgType === 'document') {
  messageType = 'document';
  text = msg.document?.caption || '';
  mediaInfo = {
    mediaId: msg.document?.id || msg.id,
    mimetype: msg.document?.mime_type || 'application/pdf',
    fileName: msg.document?.filename || 'contrato_whatsapp',
    sha256: msg.document?.sha256
  };
} else if (msgType === 'image') {
  messageType = 'image';
  text = msg.image?.caption || '';
  mediaInfo = {
    mediaId: msg.image?.id || msg.id,
    mimetype: msg.image?.mime_type || 'image/jpeg',
    sha256: msg.image?.sha256
  };
} else {
  // Unsupported message type (sticker, audio, etc.) — skip
  return [];
}

return [{
  json: {
    phone,
    phoneNumberId,
    messageType,
    text,
    mediaInfo,
    isNewConversation,
    messageId: msg.id,
    conversationId: body.conversation?.id,
    timestamp: new Date().toISOString()
  }
}];

// Get/Create Session - Query whatsapp_sessions table
const phone = $input.first().json.phone;

const SUPABASE_URL = 'https://oqipslfzbeioakfllohm.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY || $env.SUPABASE_ANON_KEY || '';

let session = null;

try {
  const response = await fetch(
    `${SUPABASE_URL}/rest/v1/whatsapp_sessions?phone_number=eq.${phone}&select=*`,
    {
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json'
      }
    }
  );
  const data = await response.json();
  if (data && data.length > 0) {
    session = data[0];
  }
} catch (e) {
  // Session lookup failed, will create new
}

// Create session if not exists
if (!session) {
  try {
    const createResponse = await fetch(
      `${SUPABASE_URL}/rest/v1/whatsapp_sessions`,
      {
        method: 'POST',
        headers: {
          'apikey': SUPABASE_KEY,
          'Authorization': `Bearer ${SUPABASE_KEY}`,
          'Content-Type': 'application/json',
          'Prefer': 'return=representation'
        },
        body: JSON.stringify({
          phone_number: phone,
          state: 'IDLE',
          message_count_today: 0,
          created_at: new Date().toISOString(),
          last_message_at: new Date().toISOString()
        })
      }
    );
    const created = await createResponse.json();
    session = Array.isArray(created) ? created[0] : created;
    session._isNew = true;
  } catch (e) {
    session = {
      phone_number: phone,
      state: 'IDLE',
      message_count_today: 0,
      _isNew: true
    };
  }
}

return [{
  json: {
    ...$input.first().json,
    session: session,
    isNewUser: session._isNew === true
  }
}];

// Welcome Message - Send to first-time users via Kapso API
const input = $input.first().json;
const phone = input.phone;
const phoneNumberId = input.phoneNumberId;

const KAPSO_API_KEY = $env.KAPSO_API_KEY || '';

const welcomeText = '*Bienvenido a InmoLawyer* \u2696\uFE0F\n\nSoy tu asistente legal especializado en *arrendamiento de vivienda urbana* en Colombia.\n\n*\u00BFQu\u00E9 puedo hacer por ti?*\n\n1\uFE0F\u20E3 *Consultas legales*: Escr\u00EDbeme cualquier pregunta sobre tu contrato de arriendo y te responder\u00E9 bas\u00E1ndome en la Ley 820 de 2003.\n\n2\uFE0F\u20E3 *Analizar contratos*: Env\u00EDame una foto o documento PDF de tu contrato y lo analizar\u00E9 para detectar cl\u00E1usulas abusivas.\n\n*Ejemplos de preguntas:*\n\u2022 \"Mi arrendador me pide dep\u00F3sito en efectivo, \u00BFes legal?\"\n\u2022 \"\u00BFCu\u00E1nto me pueden subir el arriendo este a\u00F1o?\"\n\u2022 \"Quiero terminar mi contrato anticipadamente\"\n\n\u00A1Escr\u00EDbeme tu consulta!';

try {
  await fetch(
    `https://api.kapso.ai/meta/whatsapp/v1/${phoneNumberId}/messages`,
    {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-API-Key': KAPSO_API_KEY
      },
      body: JSON.stringify({
        messaging_product: 'whatsapp',
        to: phone,
        type: 'text',
        text: { body: welcomeText }
      })
    }
  );
} catch (e) {
  // Welcome message send failed, continue anyway
}

return [{ json: { ...input, welcomeSent: true } }];

// Prepare Chat Request - Format for legal consultation
const input = $input.first().json;
const session = input.session;
const text = input.text;
const phone = input.phone;

let pregunta = text;
let contratoId = null;
let contexto = 'general';

// If session is CHATTING and has an active contract, include contract context
if (session.state === 'CHATTING' && session.active_contrato_id) {
  contratoId = session.active_contrato_id;
  contexto = 'contrato';
  pregunta = text;
}

// Check for special commands
const textLower = text.toLowerCase().trim();
if (textLower === 'menu' || textLower === 'men\u00FA' || textLower === 'inicio' || textLower === 'ayuda') {
  return [{
    json: {
      ...input,
      isSpecialCommand: true,
      commandType: 'menu'
    }
  }];
}

return [{
  json: {
    ...input,
    isSpecialCommand: false,
    requestBody: {
      pregunta: pregunta,
      contratoId: contratoId,
      contexto: contexto,
      phone: phone
    }
  }
}];

// Download Media - Get document/image via Kapso / Meta Cloud API
const input = $input.first().json;
const phoneNumberId = input.phoneNumberId;
const mediaId = input.mediaInfo?.mediaId;

const KAPSO_API_KEY = $env.KAPSO_API_KEY || '';

let base64Data = null;
let mimetype = input.mediaInfo?.mimetype || 'application/octet-stream';
let fileName = input.mediaInfo?.fileName || 'contrato_whatsapp';

if (!mediaId) {
  return [{
    json: {
      ...input,
      mediaError: true,
      errorMessage: 'No se encontr\u00F3 el archivo en el mensaje. Por favor env\u00EDalo de nuevo.'
    }
  }];
}

try {
  // Step 1: Get media URL from Meta via Kapso
  const urlResponse = await fetch(
    `https://api.kapso.ai/meta/whatsapp/v1/${phoneNumberId}/media/${mediaId}`,
    {
      headers: {
        'X-API-Key': KAPSO_API_KEY
      }
    }
  );
  const urlData = await urlResponse.json();
  const mediaUrl = urlData.url;

  if (!mediaUrl) {
    throw new Error('No media URL returned');
  }

  // Step 2: Download the actual file
  const fileResponse = await fetch(mediaUrl, {
    headers: {
      'X-API-Key': KAPSO_API_KEY
    }
  });
  const arrayBuffer = await fileResponse.arrayBuffer();
  const buffer = Buffer.from(arrayBuffer);
  base64Data = buffer.toString('base64');
  mimetype = fileResponse.headers.get('content-type') || mimetype;
} catch (e) {
  return [{
    json: {
      ...input,
      mediaError: true,
      errorMessage: 'No se pudo descargar el archivo. Por favor int\u00E9ntalo de nuevo.'
    }
  }];
}

return [{
  json: {
    ...input,
    mediaError: false,
    base64Data: base64Data,
    mimetype: mimetype,
    fileName: fileName
  }
}];

// Format WhatsApp Response - Convert AI response for WhatsApp
const input = $input.first().json;

let responseText = '';

// Handle different response shapes
if (input.respuesta) {
  responseText = input.respuesta;
} else if (input.response) {
  responseText = input.response;
} else if (input.text) {
  responseText = input.text;
} else if (input.analisis) {
  // Contract analysis response
  const analisis = typeof input.analisis === 'string' ? JSON.parse(input.analisis) : input.analisis;
  const score = analisis.score_riesgo || input.scoreRiesgo || input.score_riesgo || 0;

  let emoji = '\u2705';
  if (score > 75) emoji = '\uD83D\uDED1';
  else if (score > 50) emoji = '\u26A0\uFE0F';
  else if (score > 25) emoji = '\uD83D\uDFE1';

  responseText = `${emoji} *An\u00E1lisis de tu Contrato*\n\n`;
  responseText += `*Nivel de riesgo:* ${score}/100\n\n`;

  if (analisis.resumen) {
    responseText += `*Resumen:* ${analisis.resumen}\n\n`;
  }

  if (analisis.alertas && analisis.alertas.length > 0) {
    responseText += `*Alertas encontradas:*\n\n`;
    for (const alerta of analisis.alertas) {
      let alertaEmoji = '\u2139\uFE0F';
      if (alerta.tipo === 'danger') alertaEmoji = '\uD83D\uDED1';
      else if (alerta.tipo === 'warning') alertaEmoji = '\u26A0\uFE0F';
      else if (alerta.tipo === 'success') alertaEmoji = '\u2705';

      responseText += `${alertaEmoji} *${alerta.titulo}*\n`;
      responseText += `${alerta.descripcion}\n`;
      if (alerta.referencia_legal) {
        responseText += `_Ref: ${alerta.referencia_legal}_\n`;
      }
      responseText += `\n`;
    }
  }

  if (analisis.recomendaciones && analisis.recomendaciones.length > 0) {
    responseText += `*Recomendaciones:*\n`;
    for (const rec of analisis.recomendaciones) {
      responseText += `\u2022 ${rec}\n`;
    }
  }
} else if (input.mediaError) {
  responseText = input.errorMessage || 'No se pudo procesar el archivo enviado.';
} else {
  responseText = 'Lo siento, no pude procesar tu solicitud. Por favor int\u00E9ntalo de nuevo.';
}

// Convert markdown headers to WhatsApp bold
responseText = responseText.replace(/^###\s*(.+)$/gm, '*$1*');
responseText = responseText.replace(/^##\s*(.+)$/gm, '*$1*');
responseText = responseText.replace(/^#\s*(.+)$/gm, '*$1*');

// Convert markdown bold **text** to WhatsApp bold *text*
responseText = responseText.replace(/\*\*(.+?)\*\*/g, '*$1*');

// Convert markdown links [text](url) to just text (url)
responseText = responseText.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '$1 ($2)');

// Truncate to 4096 chars if needed (WhatsApp limit)
if (responseText.length > 4096) {
  responseText = responseText.substring(0, 4050) + '\n\n_... Respuesta truncada. Escribe "m\u00E1s" para continuar._';
}

// Get phone and phoneNumberId from upstream nodes
const phone = input.phone || $('Filter & Parse').first().json.phone;
const phoneNumberId = input.phoneNumberId || $('Filter & Parse').first().json.phoneNumberId;

return [{
  json: {
    phone: phone,
    phoneNumberId: phoneNumberId,
    formattedResponse: responseText,
    originalInput: input
  }
}];

// Update Session - Update whatsapp_sessions table
const input = $input.first().json;
const phone = input.phone || input.originalInput?.phone;

const SUPABASE_URL = 'https://oqipslfzbeioakfllohm.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY || $env.SUPABASE_ANON_KEY || '';

// Determine new state based on what happened
let newState = 'CHATTING';
const originalInput = input.originalInput || {};
if (originalInput.analisis || originalInput.contratoId) {
  newState = 'CHATTING';
}

try {
  await fetch(
    `${SUPABASE_URL}/rest/v1/whatsapp_sessions?phone_number=eq.${phone}`,
    {
      method: 'PATCH',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        state: newState,
        last_message_at: new Date().toISOString(),
        message_count_today: (originalInput.session?.message_count_today || 0) + 1,
        active_contrato_id: originalInput.analisis?.contratoId || originalInput.session?.active_contrato_id || null
      })
    }
  );
} catch (e) {
  // Session update failed, non-critical
}

return [{ json: { success: true, phone: phone, state: newState } }];
